*�����������������9)"""
BrowserExt

An OP browser with flexible functionality and layout
"""

TDF = op.TDModules.mod.TDFunctions

class BrowserExt:
	"""
	BrowserExt description
	"""
	def __init__(self, ownerComp):
		self.ownerComp = ownerComp
		TDF.createProperty(self, 'EditorPaneMode', False, dependable=True,
						   readOnly=True)
		self.editorPane = None # for EditorPaneMode only
		# relevant ops
		self.TreeLister = ownerComp.op('treePanel/opFindTreeLister')
		self.contextPath = ownerComp.op('header/contextPath')
		self.BrowserParameters = ownerComp.op('browserParameters')
		self.Window = ownerComp.op('window1')
		# available panels
		self.TreePanel = ownerComp.op('treePanel')
		self.ViewerPanel = ownerComp.op('viewerPanel')
		self.ParametersPanel = ownerComp.op('parametersPanel')
		self.HeaderPanel = ownerComp.op('header')
		# available panes
		self.Panes = [0,0,0]
		self.Panes[0] = ownerComp.op('splitPanes/pane0')
		self.Panes[1] = ownerComp.op('splitPanes/pane1')
		self.Panes[2] = ownerComp.op('pane2')
		self.SplitPanes = ownerComp.op('splitPanes')
		self.AllPanes = ownerComp.op('panes')
		# dividers
		self.SplitDivider = ownerComp.op('splitPanes/panelDivider')
		self.MainDivider = ownerComp.op('panelDivider')

		self.HiddenByAdapt = [False, False, False] # sized out panes
		self.paneConfigDict = {
			# split orientation, main orientation, split first
			'Horizontal': ['Horizontal', 'Horizontal', True],
			'Vertical': ['Vertical', 'Vertical', True],
			'Split_Left': ['Vertical', 'Horizontal', True],
			'Split_Right': ['Vertical', 'Horizontal', False],
			'Split_Bottom': ['Horizontal', 'Vertical', False],
			'Split_Top': ['Horizontal', 'Vertical', True],
		}
		if not(ownerComp.par.Component.eval()):
			self.Component = root

		self.cloneRefresh()

	def cloneRefresh(self):
		# the following just refreshes everything so that clones don't mess up
		# guts
		run('args[0].onChangeShowPanel(args[0].ownerComp.par.Showtree)',
								self, delayFrames=1, delayRef=op.TDResources)
		run('args[0].onChangeShowPanel(args[0].ownerComp.par.Showparameters)',
								self, delayFrames=1, delayRef=op.TDResources)
		run('args[0].onChangeShowPanel(args[0].ownerComp.par.Showviewer)',
								self, delayFrames=1, delayRef=op.TDResources)
		run('args[0].onChangeShowPanel(args[0].ownerComp.par.Showheader)',
								self, delayFrames=1, delayRef=op.TDResources)

	@property
	def Component(self):
		return self.ownerComp.par.Component.eval()
	@Component.setter
	def Component(self, val):
		if isinstance(val, OP):
			val = val.path
		if val.endswith('/') and len(val) > 1:
			val = val[:-1]
		o = op(val)
		if o:
			self.contextPath.par.Currentop = o.path
			self.ownerComp.par.Component = o.path
		else:
			self.ownerComp.par.Component = self.contextPath.par.Currentop
		self.CurrentOP = self.ownerComp.par.Component

	@property
	def CurrentOP(self):
		self.ownerComp.par.Component.eval()
		if self.TreeLister.CurrentOP is None:
			self.TreeLister.CurrentOP = self.Component
		return self.TreeLister.CurrentOP or self.Component
	@CurrentOP.setter
	def CurrentOP(self, val):
		if not isinstance(val, OP):
			val = op(val)
		self.TreeLister.CurrentOP = val

	@property
	def SelectedPaths(self):
		return self.TreeLister.SelectedPaths
	@SelectedPaths.setter
	def SelectedPaths(self, val):
		return self.TreeLister.FromPathsSelectRows(val)

	@property
	def panePanels(self):
		panels = [getattr(self, p + 'Panel') for p in self.orderedPanelNames]
		paneConfigInfo = self.paneConfigInfo
		if paneConfigInfo[2]:
			return panels
		else:
			return [panels[1], panels[2], panels[0]]

	def paneDisplay(self, paneNumber):
		panePanels = self.panePanels
		return panePanels[paneNumber] == self.TreePanel \
				or panePanels[paneNumber] == self.ViewerPanel \
										and self.ownerComp.par.Showviewer \
				or panePanels[paneNumber] == self.ParametersPanel \
										and self.ownerComp.par.Showparameters

	def onWidthHeightChange(self, info=None):
		if self.ownerComp.par.Adapttosize.eval() == 'Off':
			for pane in range(3):
				self.SetPaneDisplay(pane)
		else:
			self.SplitDivider.ConstrainPosition()
			self.MainDivider.ConstrainPosition()

			# Adapt to size code
			configInfo = self.paneConfigInfo
			self.HiddenByAdapt = [False, False, False]
			for pane in range(3):
				self.SetPaneDisplay(pane)
			paneMins = self.paneMins
			# preserved panel info
			panelName = self.ownerComp.par.Adapttosize.eval().split('_')[1]
			panel = getattr(self, panelName + 'Panel')
			panelPaneIndex = self.panePanels.index(panel)
			if not self.Panes[panelPaneIndex].par.display.eval():
				self.HiddenByAdapt = [True, True, True]
				for pane in range(3):
					self.SetPaneDisplay(pane)
				return

			if configInfo[1] == 'Horizontal':
				totalSize = self.AllPanes.width
			else:
				totalSize = self.AllPanes.height
			if panelPaneIndex == 2:
				# preserve non-split pane
				if totalSize < paneMins[2] + paneMins[3]:
					if configInfo[0] == configInfo[1]:
						self.HiddenByAdapt[1] = True
						self.Panes[1].par.display = False
						paneMins = self.paneMins
						if totalSize < paneMins[2] + paneMins[3]:
							self.HiddenByAdapt[0] = True
							self.Panes[0].par.display = False
						else:
							self.HiddenByAdapt[0] = False
							self.SetPaneDisplay(0)
					else:
						self.HiddenByAdapt[0] = self.HiddenByAdapt[1] = True
						self.Panes[0].par.display = False
						self.Panes[1].par.display = False
				else:
					self.HiddenByAdapt[0] = self.HiddenByAdapt[1] = False
					self.SetPaneDisplay(0)
					self.SetPaneDisplay(1)
			else:
				# preserve a split pane
				testPane = 0 if panelPaneIndex == 1 else 1
				if totalSize < paneMins[2] + paneMins[3]:
					self.HiddenByAdapt[2] = True
					self.Panes[2].par.display = False
				else:
					self.HiddenByAdapt[2] = False
					self.SetPaneDisplay(2)
				if configInfo[0] == 'Horizontal':
					splitSize = self.SplitPanes.width
				else:
					splitSize = self.SplitPanes.height
				if splitSize < paneMins[0] + paneMins[1]:
					self.HiddenByAdapt[testPane] = True
					self.Panes[testPane].par.display = False
				else:
					self.HiddenByAdapt[testPane] = False
					self.SetPaneDisplay(testPane)
			run('args[0].ConstrainPosition()', self.SplitDivider, delayFrames=1)
			run('args[0].ConstrainPosition()', self.MainDivider, delayFrames=1)

	def onReorderPanes(self):
		self.onWidthHeightChange()

	@property
	def paneConfigInfo(self):
		return self.paneConfigDict[self.ownerComp.par.Paneconfiguration.eval()]

	@property
	def splitPanelIndexes(self):
		return [0,1] if self.paneConfigInfo[2] else [1,2]

	@property
	def nonSplitPanelIndex(self):
		return 2 if self.paneConfigInfo[2] else 0

	@property
	def orderedPanelNames(self):
		return self.ownerComp.par.Paneorder.eval().split('_')

	@property
	def paneMins(self):
		"""
		Minimum size for each pane

		:return: list of minimum sizes for each pane. For convenience and speed,
		 		the fourth item is the minsize for the entire split section
		"""
		paneMins = [0,0,0,0]
		splitMins = [0,0]
		paneConfigInfo = self.paneConfigInfo
		orderedPanelNames = self.orderedPanelNames
		splitPanelIndexes = self.splitPanelIndexes
		axis = 'w' if paneConfigInfo[0] == 'Horizontal' else 'h' # split
		axis2 = 'w' if paneConfigInfo[1] == 'Horizontal' else 'h' # main
		for i in range(2):
			pane = splitPanelIndexes[i]
			paneMins[i] = getattr(self.ownerComp.par,
							orderedPanelNames[pane] + 'minsize' + axis).eval()
			splitMins[i] = getattr(self.ownerComp.par, orderedPanelNames[pane]
								   	+ 'minsize' + axis2).eval() \
										if self.Panes[i].par.display else 0

		paneMins[2] = getattr(self.ownerComp.par,
				orderedPanelNames[self.nonSplitPanelIndex]
												+ 'minsize' + axis2).eval()
		if axis == axis2:
			paneMins[3] = self.ownerComp.par.Knobsize + sum(splitMins)
		else:
			paneMins[3] = max(splitMins)
		return paneMins

	def onChangeShowPanel(self, showPar=None):
		"""
		Grow Browser if necessary for change in view status of a panel

		:param showPar: which par was changed
		"""
		if showPar.name == 'Showheader':
			if showPar.eval():
				if self.ownerComp.par.Shrinkexpandforpanes.eval():
					self.ownerComp.par.h += self.HeaderPanel.height
				self.HeaderPanel.par.display = True
			else:
				if self.ownerComp.par.Shrinkexpandforpanes.eval():
					self.ownerComp.par.h -= self.HeaderPanel.height
				self.HeaderPanel.par.display = False
			return
		elif showPar.name == 'Showparameters':
			panel = self.ParametersPanel
		elif showPar.name == 'Showviewer':
			panel = self.ViewerPanel
		elif showPar.name == 'Showtree':
			panel = self.TreePanel
		paneConfigInfo = self.paneConfigInfo
		panePanels = self.panePanels
		panelPaneIndex = panePanels.index(panel)

		if self.ownerComp.par.Shrinkexpandforpanes.eval():
			pane = self.Panes[panelPaneIndex]
			panel.par.w = panel.width
			panel.par.h = panel.height
			self.SplitPanes.par.w = self.SplitPanes.width
			self.SplitPanes.par.h = self.SplitPanes.height
			numShowingPanes = sum([self.Panes[p].par.display.eval()
								   for p in range(3)])
			if showPar.eval():
				numShowingPanes += 1
			else:
				numShowingPanes -= 1
			if numShowingPanes == 0:
				# hiding last pane
				self.ownerComp.par.h -= panel.par.h
			elif numShowingPanes == 1 and showPar.eval():
				# showing first pane
				self.ownerComp.par.h += panel.par.h
			elif panelPaneIndex == 2 \
					or panelPaneIndex == 0 and (not self.Panes[1].par.display
											or not self.Panes[2].par.display) \
					or panelPaneIndex == 1 and (not self.Panes[0].par.display
											or not self.Panes[2].par.display):
				# changing display of one of the main panes
				if panelPaneIndex == 2:
					otherPane = self.SplitPanes
				elif panelPaneIndex == 0:
					if self.Panes[1].par.display:
						otherPane = self.Panes[1]
					else:
						otherPane = self.Panes[2]
				else:
					if self.Panes[0].par.display:
						otherPane = self.Panes[0]
					else:
						otherPane = self.Panes[2]
				if pane == self.Panes[2] or otherPane == self.Panes[2]:
					paneConfigIndex = 1
					divider = self.MainDivider
				else:
					paneConfigIndex = 0
					divider = self.SplitDivider
				if paneConfigInfo[paneConfigIndex] == 'Horizontal':
					axis = 'w'
					pos = 'x'
				else:
					axis = 'h'
					pos = 'y'
				ownerSizePar = getattr(self.ownerComp.par, axis)
				if showPar.eval():
					# turning on panel
					if ownerSizePar.enable \
									and ownerSizePar.mode == ParMode.CONSTANT:
						ownerSizePar.val += self.ownerComp.par.Knobsize + \
											 getattr(panel.par, axis)
						zeroPane = pane if getattr(pane.par, pos) == 0 \
																else otherPane
						dividerPos = getattr(zeroPane.par, axis)
						setattr(divider.par, pos, dividerPos)
				else:
					# turning off panel
					if ownerSizePar.enable \
									and ownerSizePar.mode == ParMode.CONSTANT:
						ownerSizePar.val -= self.ownerComp.par.Knobsize + \
												getattr(panel.par, axis)
		self.SetPaneDisplay(panelPaneIndex)
		#pane.par.display = showPar.eval()

	def SetPaneDisplay(self, pane):
		"""
		Sets a pane to display or not, based on adapt and par
		settings
		:param pane: pane number
		"""
		panel = self.panePanels[pane]
		parValue = getattr(self.ownerComp.par, 'Show'+panel.name[:-5]).eval()
		self.Panes[pane].par.display = parValue \
						   and (self.ownerComp.par.Adapttosize.eval() == 'Off'
							 				or not self.HiddenByAdapt[pane])

	def OpenToPath(self, path, doRefresh=True):
		"""
