		if par.name in ['Showparameters', 'Showviewer', 'Showtree',
						'Showheader']:
			self.onChangeShowPanel(par)
			if par.name == 'Showheader':
				for pName in ['Editsettingsbutton', 'Showviewerbutton',
						 		'Showparametersbutton', 'Showtreebutton',
							  	'Setcomponentwithdrop', 'Pathrightclickmenu']:
					getattr(self.ownerComp.par, pName).enable = par.eval()
			elif par.name == 'Showviewer':
				for pName in ['Viewerinteractionbutton',
							  						'Allowviewerinteraction']:
					getattr(self.ownerComp.par, pName).enable = par.eval()
		elif par.name in ['Paneorder', 'Paneconfiguration']:
			self.onReorderPanes()
		# self.TreeLister.ReloadInput()
		elif par.name == 'Component':
			self.Component = par.eval()
			if self.EditorPaneMode:
				self.editorPane.owner = self.Component
		elif par.name == 'Limitmaxdepth':
			self.ownerComp.par.Maxdepth.enable = par.eval()
