		if par.name == 'Editscope':
			self.scopePanel.openViewer()
		elif par.name == 'Editsettings':
			self.BrowserParameters.openViewer()
		elif par.name == 'Openwindow':
			self.Window.par.winopen.pulse()
		elif par.name == 'Closewindow':
			self.Window.par.winclose.pulse()
		elif par.name == 'Editcolumndefinitions':
			self.TreePanel.op('config/colDefineOptions').openViewer()
		elif par.name == 'Help':
			ui.viewFile('http://www.derivative.ca/wiki/index.php?title='
						'Palette:opBrowser')

