class DividerExt:
	"""
	DividerExt description
	"""
	def __init__(self, ownerComp):
		self.ownerComp = ownerComp
		run("op('" + ownerComp.path + "').UpdateSizes", delayFrames=1,
			delayRef=op.TDResources)

	def UpdateSizes(self):
		"""
		Update the 2 divided panel's sizes. This should be called whenever
		something changes that should cause a refresh.

		:return:
		"""
		zeroPanel = self.ZeroPanel
		nonZeroPanel = self.NonZeroPanel
		positionPar = self.PositionPar
		sizePar = self.SizePar
		if nonZeroPanel:
			setattr(nonZeroPanel.par, positionPar,
					getattr(self.ownerComp.par, positionPar)
						+ self.ownerComp.par.Knobsize)
			setattr(nonZeroPanel.par, sizePar,
					self.ParentSize - getattr(nonZeroPanel.par, positionPar))
		if zeroPanel:
			size = getattr(self.ownerComp.par, positionPar)
			if size >= self.ZeroPanelMinSize:
				setattr(zeroPanel.par, sizePar, size)
				setattr(zeroPanel.par, positionPar, 0)
			else:
				# allow panel to be placed offscreen to trigger scrollbars
				setattr(zeroPanel.par, sizePar, self.ZeroPanelMinSize)
				setattr(zeroPanel.par, positionPar,
						size - self.ZeroPanelMinSize)

	def onChangeParentSize(self, val, prev):
		"""
		Parent size has changed. Adjust divider position proportionally.

		:param val: current parent size
		:param prev: previous parent size
		"""
		currentPos = getattr(self.ownerComp.par, self.PositionPar).eval()
		currentPos *= val / prev
		self.ConstrainPosition(currentPos)

	def ConstrainPosition(self, pos=None):
		"""
		Keep sizes within minimums. Will cause a valid reposition

		:param pos: A proposed position, or None to use current pos
		"""
		if pos is None:
			pos = getattr(self.ownerComp.par, self.PositionPar).eval()
		# panel at 0 position
		if pos < self.ZeroPanelMinSize:
			pos = self.ZeroPanelMinSize
		# panel at non-zero position
		parentSize = self.ParentSize
		if parentSize - (pos + self.ownerComp.par.Knobsize) \
													< self.NonZeroPanelMinSize:
			pos = parentSize - \
				  (self.NonZeroPanelMinSize + self.ownerComp.par.Knobsize)
		# apply constraint
		setattr(self.ownerComp.par, self.PositionPar, pos)
		self.UpdateSizes()

	def onParValueChange(self, par, val, prev):
		if self.Horizontal:
			if par.name in ['w', 'x']:
				self.UpdateSizes()
				return
		elif par.name in ['h', 'y']:
			self.UpdateSizes()
			return
		elif par.name in ['Orientation']:
			if val == 'Vertical':
				if not self.ownerComp.panelParent().width:
					return
				self.ownerComp.par.y = \
						(self.ownerComp.par.x /
						 			self.ownerComp.panelParent().width) \
						* self.ownerComp.panelParent().height
			elif self.ownerComp.panelParent().height:
				if not self.ownerComp.panelParent().height:
					return
				self.ownerComp.par.x = \
						(self.ownerComp.par.y /
						 			self.ownerComp.panelParent().height) \
						* self.ownerComp.panelParent().width
			self.ConstrainPosition()
		elif par.name in ['Panel1', 'Panel2', 'Panel1minsize', 'Panel2minsize']:
			self.ConstrainPosition()


	@property
	def ZeroPanel(self):
		"""
		:return: The panel at location zero. Bottom (2) in Vertical orientation,
		left (1) in Horizontal.
		"""
		if self.Horizontal:
			return self.ownerComp.par.Panel1.eval()
		else:
			return self.ownerComp.par.Panel2.eval()

	@property
	def NonZeroPanel(self):
		"""
		:return: The panel at non zero location. Top (1) in Vertical
		orientation, right (2) in Horizontal.
		"""
		if self.Horizontal:
			return self.ownerComp.par.Panel2.eval()
		else:
			return self.ownerComp.par.Panel1.eval()

	@property
	def ZeroPanelMinSize(self):
		"""
		:return: Min size of the panel at location zero. Bottom (2) in Vertical
		orientation, left (1) in Horizontal.
		"""
		if self.Horizontal:
			return self.ownerComp.par.Panel1minsize.eval()
		else:
			return self.ownerComp.par.Panel2minsize.eval()

	@property
	def NonZeroPanelMinSize(self):
		"""
		:return: Min size of the panel at non zero location zero. Top (1) in
		Vertical orientation, right (2) in Horizontal.
		"""
		if self.Horizontal:
			return self.ownerComp.par.Panel2minsize.eval()
		else:
			return self.ownerComp.par.Panel1minsize.eval()

	@property
	def PositionPar(self):
		"""
		:return: 'x' if mode is horizontal else 'y'
		"""
		return 'x' if self.Horizontal else 'y'

	@property
	def SizePar(self):
		"""
		:return: 'w' if mode is horizontal else 'h'
		"""
		return 'w' if self.Horizontal else 'h'

	@property
	def ParentSize(self):
		"""
		:return: parent.width if mode is horizontal else parent.height
		"""
		return self.ownerComp.panelParent().width if self.Horizontal \
						else self.ownerComp.panelParent().height

	@property
	def hMode(self):
		return 'fixed' if self.Horizontal else 'fill'

	@property
	def vMode(self):
		return 'fill' if self.Horizontal else 'fixed'

	@property
	def Horizontal(self):
		return not self.ownerComp.par.Orientation.menuIndex

	@property
	def xRangeMin(self):
		return self.ZeroPanelMinSize if self.Horizontal else -10000

	@property
	def xRangeMax(self):
		return (self.ownerComp.panelParent().width - self.NonZeroPanelMinSize
				- self.ownerComp.par.Knobsize) if self.Horizontal else 10000

	@property
	def yRangeMin(self):
		return -10000 if self.Horizontal else self.ZeroPanelMinSize

	@property
	def yRangeMax(self):
		return 10000 if self.Horizontal else \
				(self.ownerComp.panelParent().height - self.NonZeroPanelMinSize
				 - self.ownerComp.par.Knobsize)
	@property
	def showHandle(self):
		return './handle' if self.ownerComp.par.enable else ''

	@property
	def backgroundAlpha(self):
		return 1 if passive(self.ownerComp).panel.inside \
									and self.ownerComp.par.enable else 0.8

